  function activateDocument(view, name) {
    state.activeDocuments[view] = name;
    if (view === "verify" && VERIFY_MODE_BY_DOCUMENT[name]) state.verifyMode = VERIFY_MODE_BY_DOCUMENT[name];
    if (view === "models" && MODEL_BY_DOCUMENT[name]) state.selectedModel = MODEL_BY_DOCUMENT[name];
  }

  function commercialDocumentForName(view, name) {
    return state.commercialDocuments.find((document) => document.owner === view && document.name === name) || null;
  }

  function activeCommercialDocument(view = state.view) {
    return commercialDocumentForName(view, state.activeDocuments[view]);
  }

  function modelBrowserGroup(modelId) {
    if (modelId === "OPA189_A") return "OPA189_A";
    if (modelId === "sensor_bridge") return "sensor_bridge";
    if (modelId === "VBIC_1.3" || modelId === "HICUM_L2") return "bjt";
    if (modelId === "LTRA") return "passives";
    if (modelId === "demo180_nch") return "demo180";
    return "mos";
  }

  function resolvedDocuments(view) {
    const primaryDocuments = (docSets[view] || []).map((doc, index) => view === "results" && index === 0 ? { ...doc, name: `Run ${state.runId} · PVT ${state.resultManifest?.runSet.pointCount || PVT_RUN_POINTS.length}` } : { ...doc });
    const commercialDocuments = state.commercialDocuments
      .filter((document) => document.owner === view)
      .map((document) => ({ name: document.name, icon: document.icon }));
    return [...primaryDocuments, ...commercialDocuments];
  }

