      "export-license-usage": ["Export license usage", "LICENSING · AUDIT EXPORT", "Export usage CSV", "Export the filtered checkout, denial, failover, duration, source, user/device, and run records without server credentials.", [["Period", "Last 30 days"], ["Features", "All features"], ["Format", ["CSV + metadata JSON", "XLSX"]]]],
      "close-unmodified-documents": ["Close unmodified documents", "WINDOW · DOCUMENT MANAGEMENT", "Close unmodified", "Close saved and immutable documents while preserving modified documents, active jobs, and reconstructable view state.", [["Documents", "3 unmodified"], ["Modified", "1 · keep open"], ["Restore on launch", ["Keep remembered state", "Remove closed documents"]]]],
      "reopen-last-session": ["Reopen last document session", "WINDOW · SESSION RESTORE", "Reopen session", "Restore the last qualified document set, workspace ownership, active tabs, viewer state, and safe dock layout.", [["Session", "2026-07-10 13:42 · 7 documents"], ["Modified documents", "recovery copies only"], ["Result views", "reconstruct from immutable datasets"]]],
