      phase: '<path class="trace t1" d="M40 48 C90 60 112 88 155 99 S220 122 272 139 S350 161 410 180 S488 198 560 216"/><path class="viewer-mask" d="M40 82 L145 112 L260 150 L380 184 L560 225"/>',
      smith: '<circle class="smith-main" cx="300" cy="135" r="104"/><circle class="smith-circle" cx="352" cy="135" r="52"/><circle class="smith-circle" cx="404" cy="135" r="26"/><path class="smith-grid" d="M196 135H404 M300 31C246 66 246 204 300 239 M300 31C354 66 354 204 300 239"/><path class="trace t1" d="M225 170 C254 91 322 65 364 112 S366 188 325 196 S260 185 245 151"/>',
      polar: '<circle class="smith-main" cx="300" cy="135" r="104"/><circle class="smith-circle" cx="300" cy="135" r="69"/><circle class="smith-circle" cx="300" cy="135" r="35"/><path class="smith-grid" d="M196 135H404 M300 31V239 M226 61L374 209 M374 61L226 209"/><path class="trace t1" d="M300 135 C350 112 388 145 363 183 S285 215 250 178 S240 94 289 73"/>',
      eye: '<path class="trace eye1" d="M40 210 C125 210 130 55 230 55 S345 210 560 210"/><path class="trace eye2" d="M40 55 C125 55 130 210 230 210 S345 55 560 55"/><path class="trace eye3" d="M40 203 C130 196 143 67 230 62 S346 198 560 205"/><path class="viewer-mask eye-mask" d="M250 105 L320 105 L350 165 L220 165 Z"/>',
      bathtub: '<path class="trace t1" d="M40 50 C110 55 162 73 215 150 S365 150 420 74 S505 53 560 50"/><path class="viewer-mask" d="M220 170 H380"/>',
      margin: '<path class="trace eye1" d="M40 210 C125 210 130 55 230 55 S345 210 560 210"/><path class="trace eye2" d="M40 55 C125 55 130 210 230 210 S345 55 560 55"/><rect class="margin-box" x="232" y="96" width="126" height="80"/>',
      pz: '<path class="smith-grid" d="M40 135H560 M300 24V246"/><g class="pz-poles"><path d="M175 82l12 12m0-12l-12 12M215 188l12 12m0-12l-12 12M404 105l12 12m0-12l-12 12"/></g><g class="pz-zero"><circle cx="350" cy="135" r="8"/><circle cx="447" cy="184" r="8"/></g>',
