      contour: '<ellipse class="contour c1" cx="300" cy="135" rx="170" ry="86"/><ellipse class="contour c2" cx="300" cy="135" rx="124" ry="61"/><ellipse class="contour c3" cx="300" cy="135" rx="74" ry="36"/><circle class="contour-optimum" cx="318" cy="128" r="5"/>',
      field: '<defs><linearGradient id="fieldGradient" x1="0" x2="1"><stop offset="0" stop-color="#2563eb"/><stop offset=".5" stop-color="#54d58c"/><stop offset="1" stop-color="#ef625e"/></linearGradient></defs><path class="field-shape" d="M74 210 L132 67 L248 42 L338 91 L468 54 L536 197 L410 226 L250 202 Z"/><path class="field-current" d="M100 185 C180 80 230 190 310 88 S440 180 510 74"/>',
