          metrics: [["Candidate", candidate.id, candidate.frozen ? "frozen · immutable scope" : "draft · scope editable", candidate.frozen ? "ok" : "warn"], ["Authoritative gates", `${gateCounts.pass || 0} / ${RELEASE_GATES.length}`, `${gateCounts.block || 0} blocking · ${gateCounts.review || 0} review`, "warn"], ["Approvals", `${candidate.signedApprovals} / ${candidate.requiredApprovals}`, candidate.approvalState, candidate.signedApprovals === candidate.requiredApprovals ? "ok" : "warn"], ["Package", candidate.packageState, candidate.status === "released" ? "signed release" : "promotion unavailable", candidate.status === "released" ? "ok" : "warn"]],
