      return { title: "Review report artifact handoff", eyebrow: "REPORT AUTHORING · RELEASE-CLOSURE INPUT", primary: compatible ? "Attach review artifact" : "Close", body: `<div class="concept-banner ${compatible ? "" : "error"}">${iconSvg(compatible ? "info" : "warning")}${compatible ? `${currentReportId} and ${candidate.id} reference the same immutable Run ${state.resultManifest.id}. Attaching records a candidate reference; release closure still validates and packages it.` : `${currentReportId} is bound to Run ${state.resultManifest.id}, but ${candidate.id} is bound to Run ${candidate.resultBinding.resultId}. Rebind the draft candidate or generate/select the report for its exact result before handoff.`}</div><table class="data-table"><thead><tr><th>Artifact</th><th>Candidate</th><th>Result compatibility</th><th>Gate disclosure</th><th>Effect</th></tr></thead><tbody><tr><td>${currentReportId}</td><td>${candidate.id} · ${candidate.frozen ? "frozen" : "draft"}</td><td class="${compatible ? "ok-text" : "error-text"}">${compatible ? `exact Run ${state.resultManifest.id}` : `Run ${state.resultManifest.id} ≠ Run ${candidate.resultBinding.resultId}`}</td><td class="warn-text">2 block · 1 review</td><td>${compatible ? "reference only" : "no change"}</td></tr></tbody></table>${compatible ? `<div class="form-grid"><label class="field-block"><span>Blocked-gate presentation</span><select class="select"><option>Mandatory detailed disclosure</option></select></label><label class="field-block"><span>Review watermark</span><select class="select"><option>NON-RELEASE · GATES OPEN</option></select></label><label class="field-block"><span>Change note</span><input class="input" value="Attach ${currentReportId} for Run ${state.resultManifest.id}"></label></div>` : '<div class="dialog-toolbar"><button class="button" data-surface-action="release-freeze-candidate">Review candidate binding…</button><button class="button" data-surface-action="release-cockpit">Open release closure</button></div>'}` };
