    if (action === "model-rerun-vector") return { title: "Rerun exact model vector", eyebrow: "MODELS · REPRODUCIBLE QUALIFICATION", primary: "Queue exact rerun", body: `${workflowArchetypeMarkup(action, { title: "model vector rerun", description: "Freeze the vector, oracle, model digest, compiler, runtimes, numeric policy and comparison tolerance before dispatch.", fields: [["Vector", "ACQ-019 · BSIM4 charge"], ["Runtimes", ["Desktop + web + mobile", "Desktop only", "All qualified interpreters"]], ["Oracle", "ngspice 45 · digest 917a…812c"], ["Comparison", "relative + absolute · fail closed"]] })}` };
