    if (action === "export-verification-report") return { title: "Export verification report", eyebrow: "REPORTING · APPROVED TEMPLATE · TRACEABLE PACKAGE", primary: "Export report package", body: `<div class="form-grid"><label class="field-block"><span>Report document</span><select class="select"><option>AFE release verification · current draft</option><option>Design review summary</option><option>Model qualification</option></select></label><label class="field-block"><span>Template revision</span><select class="select"><option>Release report 4.2 · organization approved</option></select></label><label class="field-block"><span>Formats</span><select class="select"><option>PDF/A + HTML + canonical JSON</option><option>PDF/A only</option></select></label><label class="field-block"><span>Signature state</span><select class="select"><option>Draft watermark · 2 release gates open</option><option>Request signatures after generation</option></select></label></div><table class="data-table"><thead><tr><th>Section</th><th>Source</th><th>Figures / tables</th><th>Status</th></tr></thead><tbody><tr><td>Configuration</td><td>working + dependency manifests</td><td>4 tables</td><td class="ok-text">current</td></tr><tr><td>Nominal / PVT</td><td>Run 41</td><td>6 figures · 3 tables</td><td class="ok-text">current</td></tr><tr><td>Yield</td><td>yield_1000</td><td>4 figures · 2 tables</td><td class="warn-text">below gate</td></tr><tr><td>Physical</td><td>DRC Run 42</td><td>marker summary</td><td class="error-text">23 blocking</td></tr></tbody></table>` };

    if (action === "new-design-variable") return { title: "Create design variable", eyebrow: "SIMULATION PLAN · TYPED PARAMETER · DEPENDENCY PREVIEW", primary: "Create variable", body: `<div class="dialog-split"><section><div class="form-grid one"><label class="field-block"><span>Name</span><input class="input mono" value="RLOAD_TEST"></label><label class="field-block"><span>Expression</span><input class="input mono" value="10 kohm"></label><label class="field-block"><span>Quantity</span><select class="select"><option>Resistance</option><option>Capacitance</option><option>Voltage</option><option>Current</option><option>Temperature</option><option>Dimensionless</option></select></label><label class="field-block"><span>Ownership scope</span><select class="select"><option>Lab characterization · testbench</option><option>Project</option><option>Selected cell</option><option>Selected analysis only</option></select></label><label class="field-block"><span>Description</span><input class="input" value="Verification load used by characterization plans"></label></div></section><section><div class="section-head"><strong>Constraints and consumers</strong></div><div class="form-grid one"><label class="field-block"><span>Allowed range</span><input class="input mono" value="1 kohm … 1 Mohm"></label><label class="field-block"><span>Sweep eligibility</span><select class="select"><option>Nested sweep + optimization</option><option>Optimization only</option><option>Fixed parameter</option></select></label><label class="field-block"><span>Override policy</span><select class="select"><option>Explicit test-local override</option><option>Inherit owner only</option></select></label></div><div class="property-list"><div class="property-row"><span>Resolved value</span><span class="property-value ok-text mono">10.0000 kΩ</span></div><div class="property-row"><span>Name conflicts</span><span class="property-value ok-text">none</span></div><div class="property-row"><span>Prospective consumers</span><span class="property-value">TRAN · DC sweep · optimization</span></div><div class="property-row"><span>Result effect</span><span class="property-value warn-text">dependent future runs only</span></div></div></section></div>` };
    if (action === "add-output") return { title: "Add saved output or derived expression", eyebrow: "SIMULATION PLAN · DATA CONTRACT · STORAGE IMPACT", primary: "Add output", body: `<div class="dialog-split"><section><div class="form-grid one"><label class="field-block"><span>Output kind</span><select class="select"><option>Raw voltage / current</option><option>Derived expression</option><option>Device operating-point quantity</option><option>Noise contributor</option><option>RF port quantity</option></select></label><label class="field-block"><span>Name</span><input class="input mono" value="V(afe_out)"></label><label class="field-block"><span>Source or expression</span><textarea class="input mono" rows="3">V(afe_out)</textarea></label><label class="field-block"><span>Compatible analyses</span><select class="select"><option>OP + TRAN + AC</option><option>All compatible analyses</option><option>Selected analysis only</option></select></label></div></section><section><div class="section-head"><strong>Save, precision, and provenance</strong></div><div class="form-grid one"><label class="field-block"><span>Save policy</span><select class="select"><option>Every accepted point</option><option>Selected + final points</option><option>On demand from retained state</option><option>Failure diagnostics only</option></select></label><label class="field-block"><span>Stored precision</span><select class="select"><option>f64 / complex128</option><option>f32 display cache + full source precision</option></select></label><label class="field-block"><span>Streaming</span><select class="select"><option>Live plot · adaptive display decimation</option><option>Store only</option></select></label></div><div class="property-list"><div class="property-row"><span>Inferred unit</span><span class="property-value ok-text">volts</span></div><div class="property-row"><span>Estimated increment</span><span class="property-value">31 MiB / 15 PVT points</span></div><div class="property-row"><span>Expression validity</span><span class="property-value ok-text">all references resolved</span></div><div class="property-row"><span>Consumers</span><span class="property-value">new output · no existing dependencies</span></div></div></section></div>` };
    if (action === "preview-task-matrix") return { title: "Preview expanded task matrix", eyebrow: "SIMULATION PLAN · RUN-SET EXPANSION · RESOURCE FORECAST", primary: "Accept task preview", body: `<div class="verify-kpis"><div class="verify-kpi"><span class="kpi-label">PVT points</span><div class="kpi-value">15</div><div class="kpi-foot">5 corners × 3 temperatures</div></div><div class="verify-kpi"><span class="kpi-label">Analyses</span><div class="kpi-value">8</div><div class="kpi-foot">dependency ordered</div></div><div class="verify-kpi"><span class="kpi-label">Tasks</span><div class="kpi-value">120</div><div class="kpi-foot">112 checkpoint-reusable</div></div><div class="verify-kpi"><span class="kpi-label">Estimate</span><div class="kpi-value">28.42 s</div><div class="kpi-foot">12 qualified local slots</div></div></div><table class="data-table"><thead><tr><th>Stage</th><th>Expansion</th><th>Tasks</th><th>Parallelism</th><th>Checkpoint</th><th>Failure policy</th></tr></thead><tbody><tr><td>OP</td><td>15 PVT</td><td>15</td><td>12</td><td>per point</td><td>block dependent analyses</td></tr><tr><td>TRAN</td><td>15 PVT</td><td>15</td><td>12</td><td>transactional</td><td>retain partial + continue</td></tr><tr><td>AC / NOISE / STB</td><td>15 PVT × 3</td><td>45</td><td>12</td><td>reuse OP</td><td>continue independent tasks</td></tr><tr><td>DC / SENS / FOUR</td><td>15 PVT × 3</td><td>45</td><td>12</td><td>reuse compatible state</td><td>continue independent tasks</td></tr></tbody></table><div class="dialog-note-grid"><div><strong>Frozen at execution</strong><p>Design revision, models, run-set dimensions, analysis options, outputs, requirements, target, and engine identity.</p></div><div><strong>Not changed here</strong><p>This preview accepts no numerical or scope changes; edit the owning setup surface to alter expansion.</p></div></div>` };
    if (action === "validate-solver-options") return { title: "Validate resolved solver options", eyebrow: "SIMULATION PLAN · NUMERICAL CONTRACT · PLATFORM PARITY", primary: "Record validation report", body: `<table class="data-table"><thead><tr><th>Contract</th><th>Resolved policy</th><th>Desktop</th><th>WebAssembly</th><th>Evidence</th></tr></thead><tbody><tr><td>Tolerances</td><td class="mono">reltol 1e−4 · vabstol 1 µV · iabstol 1 pA</td><td class="ok-text">valid</td><td class="ok-text">valid</td><td>numeric contract 1.0</td></tr><tr><td>Transient integration</td><td>Gear 2 with reviewed fallback</td><td class="ok-text">available</td><td class="ok-text">available</td><td>deterministic sequence</td></tr><tr><td>Continuation</td><td>gmin → source stepping → damped Newton</td><td class="ok-text">available</td><td class="ok-text">available</td><td>bounded retry path</td></tr><tr><td>Per-analysis overrides</td><td>8 resolved records</td><td class="ok-text">valid</td><td class="ok-text">valid</td><td>no hidden fallback</td></tr></tbody></table><div class="dialog-note-grid"><div><strong>Validation result</strong><p>All quantities, limits, convergence sequences, overrides, and target capabilities resolve without ambiguity.</p></div><div><strong>Execution meaning</strong><p>The exact resolved values—not the preset name—are frozen into every task manifest and diagnostic record.</p></div></div>` };
    if (action === "save-storage-policy") return { title: "Save streaming and retention policy", eyebrow: "SIMULATION PLAN · OUTPUT LIFECYCLE · PORTABLE PRESET", primary: "Save policy revision", body: `<div class="dialog-split"><section><div class="form-grid one"><label class="field-block"><span>Policy name</span><input class="input" value="characterization_full_precision"></label><label class="field-block"><span>Scope</span><select class="select"><option>Lab characterization plan</option><option>Project reusable preset</option><option>Organization template candidate</option></select></label><label class="field-block"><span>Live-stream behavior</span><select class="select"><option>Decimate display only; never stored data</option><option>Disable live streaming</option></select></label><label class="field-block"><span>Quota response</span><select class="select"><option>Block before execution</option><option>Require reviewed alternate store</option></select></label></div></section><section><div class="section-head"><strong>Resolved storage contract</strong></div><table class="data-table"><thead><tr><th>Class</th><th>Precision</th><th>Retention</th><th>Estimate</th></tr></thead><tbody><tr><td>Selected waveforms</td><td>f64 / complex128</td><td>project policy</td><td>576 MiB</td></tr><tr><td>Measurements</td><td>full source precision</td><td>result lifetime</td><td>12 MiB</td></tr><tr><td>Failure diagnostics</td><td>typed artifact</td><td>30 days / governed</td><td>96 MiB reserve</td></tr></tbody></table><div class="property-list"><div class="property-row"><span>Total estimate</span><span class="property-value">684 MiB</span></div><div class="property-row"><span>Available store</span><span class="property-value ok-text">82.4 GiB</span></div><div class="property-row"><span>Protected evidence</span><span class="property-value">never auto-pruned</span></div></div></section></div>` };
    if (action === "new-measurement") return { title: "Create typed measurement", eyebrow: "RESULTS · EXPRESSION · VALIDATION VECTORS", primary: "Create measurement revision", body: `<div class="dialog-split"><section><div class="form-grid one"><label class="field-block"><span>Name</span><input class="input mono" value="settling_0p1"></label><label class="field-block"><span>Domain</span><select class="select"><option>Transient</option><option>AC</option><option>Noise</option><option>Periodic / RF</option><option>Any compatible dataset</option></select></label><label class="field-block"><span>Definition</span><textarea class="input mono" rows="4">settle(V(afe_out), target=final_value(), band=0.1%)</textarea></label><label class="field-block"><span>Declared output unit</span><select class="select"><option>Infer · seconds</option><option>Explicit seconds</option></select></label></div></section><section><div class="section-head"><strong>Parameters and validation</strong></div><table class="data-table"><thead><tr><th>Parameter</th><th>Type</th><th>Default</th><th>Required</th></tr></thead><tbody><tr><td>trace</td><td>voltage trace</td><td>—</td><td>yes</td></tr><tr><td>target</td><td>voltage</td><td>final_value()</td><td>no</td></tr><tr><td>band</td><td>relative</td><td>0.1%</td><td>no</td></tr></tbody></table><div class="property-list"><div class="property-row"><span>Unit inference</span><span class="property-value ok-text">time</span></div><div class="property-row"><span>Validation vectors</span><span class="property-value ok-text">12 / 12 pass</span></div><div class="property-row"><span>Undefined behavior</span><span class="property-value">returns explicit no-crossing result</span></div></div></section></div>` };
    if (action === "import-measurement-data") return { title: "Import measurement and characterization data", eyebrow: "MODELING · DATA INGEST · AXIS MAPPING", primary: "Import validated datasets", body: `<div class="import-stepper"><span class="complete">1 Files</span><span class="active">2 Columns</span><span>3 Conditions</span><span>4 Units</span><span>5 Review</span></div><table class="data-table"><thead><tr><th>Source column</th><th>Quantity</th><th>Unit</th><th>Axis / response</th><th>Condition mapping</th><th>Status</th></tr></thead><tbody><tr><td>vgs</td><td>gate voltage</td><td>V</td><td>X axis</td><td>all rows</td><td class="ok-text">mapped</td></tr><tr><td>ids</td><td>drain current</td><td>A</td><td>response</td><td>by VDS / T</td><td class="ok-text">mapped</td></tr><tr><td>temp</td><td>temperature</td><td>°C</td><td>condition</td><td>−40, 27, 125</td><td class="ok-text">mapped</td></tr><tr><td>device</td><td>sample identifier</td><td>—</td><td>family</td><td>wafer / die</td><td class="warn-text">review hierarchy</td></tr></tbody></table><div class="form-grid"><label class="field-block"><span>Missing values</span><select class="select"><option>Preserve missing samples</option><option>Reject row</option></select></label><label class="field-block"><span>Outliers</span><select class="select"><option>Flag; never delete automatically</option></select></label></div>` };
    if (action === "extraction-templates") return { title: "Model-extraction template manager", eyebrow: "MODELS · STAGES · REUSABLE FIT POLICY", primary: "Save extraction templates", body: `<table class="data-table"><thead><tr><th>Template</th><th>Model family</th><th>Stages</th><th>Datasets</th><th>Algorithm</th><th>Version</th></tr></thead><tbody><tr><td>BSIM4 DC + CV</td><td>BSIM4</td><td>7</td><td>IV · CV · temperature</td><td>LM + SQP</td><td>4</td></tr><tr><td>Diode compact</td><td>Junction</td><td>4</td><td>IV · CV · noise</td><td>robust LM</td><td>2</td></tr><tr><td>Op-amp macro</td><td>Macro-model</td><td>6</td><td>DC · AC · transient</td><td>hybrid</td><td>8</td></tr></tbody></table><div class="dialog-toolbar"><button class="button" data-surface-action="new-extraction-template">New template…</button><button class="button" data-surface-action="clone-extraction-template">Clone version…</button><button class="button" data-surface-action="import-extraction-template">Import organization template…</button></div>` };
