    if (action === "check-and-save") { openWorkflow(action, () => runSchematicChecks({ save: true })); return; }
    if (action === "report-authoring" || action === "report-page-editor") { openCodeSurface("reports", { focusLanding: true }); return; }
    if (action === "report-page-properties") { openWorkflow("report-page-editor"); return; }
